import React, { useEffect, useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { supabase } from '../services/supabaseClient';
import { 
  LayoutDashboard, PlusCircle, List, Home, 
  CreditCard, Wallet, LogOut, User 
} from 'lucide-react';
import ModalFeedback from '../components/ModalFeedback';

const Sidebar = () => {
  const location = useLocation();
  const [perfil, setPerfil] = useState({ tipo: 'comum' });
  
  // Estado para o Modal de Sair
  const [modalLogout, setModalLogout] = useState({ isOpen: false });

  const isActive = (path) => location.pathname === path;

  useEffect(() => {
    obterPerfil();
  }, []);

  async function obterPerfil() {
    const { data: { user } } = await supabase.auth.getUser();
    if (user) {
      const { data } = await supabase
        .from('profiles')
        .select('tipo_usuario')
        .eq('id', user.id)
        .single();
      if (data) setPerfil({ tipo: data.tipo_usuario });
    }
  }

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  return (
    <>
      <style>{`
        /* --- ESTILOS MANTIDOS --- */
        .sidebar-container {
          width: 260px;
          height: 100vh;
          background: #ffffff;
          border-right: 1px solid #f1f5f9;
          padding: 30px 20px;
          position: fixed;
          left: 0;
          top: 0;
          display: flex;
          flex-direction: column;
          z-index: 1000;
          transition: all 0.3s ease;
        }

        .logo {
          display: flex;
          align-items: center;
          gap: 12px;
          font-size: 1.4rem;
          font-weight: 800;
          color: #4361ee;
          margin-bottom: 40px;
          padding-left: 10px;
        }

        .nav-list {
          display: flex;
          flex-direction: column;
          gap: 8px;
          flex: 1;
        }

        .nav-item {
          display: flex;
          align-items: center;
          gap: 12px;
          padding: 14px 18px;
          text-decoration: none;
          color: #64748b;
          font-weight: 600;
          border-radius: 14px;
          transition: all 0.2s ease;
          cursor: pointer;
          border: none;
          background: none;
          width: 100%;
          text-align: left;
          font-family: inherit;
        }

        .nav-item:hover {
          background: #f8fafc;
          color: #4361ee;
        }

        .nav-item.active {
          background: #4361ee15;
          color: #4361ee;
        }

        .logout-btn {
          margin-top: auto;
          color: #ef4444;
        }

        .logout-btn:hover {
          background: #fef2f2;
          color: #ef4444;
        }

        @media (max-width: 768px) {
          .sidebar-container {
            width: 100%;
            height: 70px;
            bottom: 0;
            top: auto;
            flex-direction: row;
            padding: 0 5px;
            border-right: none;
            border-top: 1px solid #f1f5f9;
            justify-content: space-around;
            align-items: center;
            box-shadow: 0 -4px 15px rgba(0,0,0,0.05);
          }

          .logo { display: none; }

          .nav-list {
            flex-direction: row;
            width: 100%;
            justify-content: space-around;
            gap: 0;
            flex: none;
          }

          .nav-item {
            flex-direction: column;
            gap: 4px;
            padding: 8px 4px;
            font-size: 0.6rem;
            border-radius: 10px;
            flex: 1;
            text-align: center;
            align-items: center;
          }

          .nav-item svg {
            width: 20px;
            height: 20px;
          }

          .logout-btn { margin-top: 0; }
          
          body {
            padding-bottom: 80px;
            padding-left: 0 !important;
          }
        }

        @media (min-width: 769px) {
          body { padding-left: 260px; }
        }
      `}</style>

      <aside className="sidebar-container">
        <div className="logo">
          <Wallet size={28} fill="#4361ee30" />
          <span>Finanças</span>
        </div>

        <nav className="nav-list">
          <Link to="/" className={`nav-item ${isActive('/') ? 'active' : ''}`}>
            <Home />
            <span>Início</span>
          </Link>

          {perfil.tipo === 'proprietario' && (
            <Link to="/lancamento" className={`nav-item ${isActive('/lancamento') ? 'active' : ''}`}>
              <PlusCircle />
              <span>Novo</span>
            </Link>
          )}

          <Link to="/listagem" className={`nav-item ${isActive('/listagem') ? 'active' : ''}`}>
            <List />
            <span>Extrato</span>
          </Link>

          {perfil.tipo === 'proprietario' && (
            <Link to="/cartoes" className={`nav-item ${isActive('/cartoes') ? 'active' : ''}`}>
              <CreditCard />
              <span>Cartões</span>
            </Link>
          )}

          <Link to="/dashboard" className={`nav-item ${isActive('/dashboard') ? 'active' : ''}`}>
            <LayoutDashboard />
            <span>Painel</span>
          </Link>

          <Link to="/perfil" className={`nav-item ${isActive('/perfil') ? 'active' : ''}`}>
            <User />
            <span>Perfil</span>
          </Link>

          <button 
            onClick={() => setModalLogout({ isOpen: true })} 
            className="nav-item logout-btn"
          >
            <LogOut />
            <span>Sair</span>
          </button>
        </nav>
      </aside>

      {/* Modal de Confirmação de Saída */}
      <ModalFeedback
        isOpen={modalLogout.isOpen}
        type="error" // Tons avermelhados como você pediu
        title="Encerrar Sessão?"
        message="Você terá que entrar com suas credenciais novamente para acessar o sistema."
        onClose={() => setModalLogout({ isOpen: false })}
        onConfirm={handleLogout}
      />
    </>
  );
};

export default Sidebar;
